impl Solution { pub fn largest_square_area(bl: Vec<Vec<i32>>, tr: Vec<Vec<i32>>) -> i64 { let mut black_max = 0i64; for i in 0..bl.len() { for j in i + 1..bl.len() { let black_w = 0.max(tr[i][0].min(tr[j][0]) - bl[i][0].max(bl[j][0])) as i64; let black_h = 0.max(tr[i][1].min(tr[j][1]) - bl[i][1].max(bl[j][1])) as i64; let black_s = black_w.min(black_h); black_max = black_max.max(black_s * black_s); } } black_max } }